import{_ as t,o as e,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"F07: 存貨週轉效率同業對比 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F07_存貨週轉效率同業對比_投資研究員.md","filePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F07_存貨週轉效率同業對比_投資研究員.md"}'),r={name:"審計報告庫/財務審計/8074_鉅橡/20260501/F07_存貨週轉效率同業對比_投資研究員.md"};function n(o,a,s,h,c,d){return e(),i("div",null,[...a[0]||(a[0]=[l('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的投資洞見。</p><h1 id="f07-存貨週轉效率同業對比-投資研究員-審計報告" tabindex="-1">F07: 存貨週轉效率同業對比 - 投資研究員 審計報告 <a class="header-anchor" href="#f07-存貨週轉效率同業對比-投資研究員-審計報告" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期 (Cash Cycle) 是否處於擴張狀態？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：鉅橡 2025 年存貨週轉天數 573 天，較 2024 年峰值 632 天縮短 59 天，營運週期收縮至 503 天；然相較 PCB 同業平均約 209 天，仍高出 174%（約 3.7 倍），屬供應鏈管理弱勢。</li><li><strong>風險評級</strong>：中高（現金週期 503 天，資金佔用壓力顯著）</li><li><strong>數據時效</strong>：根據截至 2025 年 12 月最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>關鍵指標對位</strong>： <ul><li>存貨週轉天數 (DIO)：2023=531 → 2024=632 → 2025=573 天</li><li>應收天數 (DSO)：2023=86 → 2024=85 → 2025=88 天</li><li>應付天數 (DPO)：2023=144 → 2024=163 → 2025=158 天</li><li>現金週期 (CCC)：2023=473 → 2024=554 → 2025=503 天</li></ul></li><li><strong>同業對位</strong>：StatementDog 顯示鉅橡營運週期 239.21 天，優於電子零組件製造業平均 364.37 天；然 PCB 同業平均僅約 209 天，鉅橡仍落後約 14%。</li><li><strong>季度趨勢</strong>：2025 Q1 DIO=619 → Q2=514 → Q3=500 → Q4=562 天，Q4 出現反轉惡化。</li><li><strong>診斷見解</strong>：鉅橡存貨週轉天數雖較 2024 年峰值改善，但絕對值仍遠超 PCB 同業水準。現金週期 503 天意味著每筆訂單從採購到收回現金需約 1.4 年，資金效率嚴重落後同業。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、存貨週轉天數年度趨勢分析" tabindex="-1">一、存貨週轉天數年度趨勢分析 <a class="header-anchor" href="#一、存貨週轉天數年度趨勢分析" aria-label="Permalink to &quot;一、存貨週轉天數年度趨勢分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：鉅橡 2025 年 DIO=573 天，較 2024 年 632 天減少 59 天（-9.3%），存貨餘額從 411M 降至 376M TWD（-8.5%）。</li><li><strong>深度見解</strong>：DIO 下降主因係存貨餘額縮減而非營業成本降低（2025 年 COGS 仍維持 ~991M TWD）。季度層面觀察，2025 Q3 曾達最低點 500 天，惟 Q4 惡化至 562 天，顯示存貨管理改善具季節性波動而非結構性突破。與 PCB 同業平均約 209 天相比，鉅橡的存貨週轉效率仍落後約 174%。</li></ul><h3 id="二、現金週期-cash-cycle-擴張壓力測試" tabindex="-1">二、現金週期 (Cash Cycle) 擴張壓力測試 <a class="header-anchor" href="#二、現金週期-cash-cycle-擴張壓力測試" aria-label="Permalink to &quot;二、現金週期 (Cash Cycle) 擴張壓力測試&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025 年現金週期 503 天，較 2024 年 554 天縮短 51 天，主因 DPO 從 163 天降至 158 天（-3.1%）及 DIO 改善。</li><li><strong>深度見解</strong>：CCC = DIO + DSO - DPO = 573 + 88 - 158 = 503 天。此數值意味著鉅橡每筆訂單需約 1.4 年才能完成「採購→生產→銷售→收款」的完整循環。相較 PCB 同業約 209 天的營運週期，鉅橡的資金佔用時間長近 2.4 倍。此差距反映鉅橡在供應鏈議價能力（DPO）與存貨去化速度（DIO）上均處於劣勢。</li></ul><h3 id="三、同業對位與競爭力評估" tabindex="-1">三、同業對位與競爭力評估 <a class="header-anchor" href="#三、同業對位與競爭力評估" aria-label="Permalink to &quot;三、同業對位與競爭力評估&quot;">​</a></h3><ul><li><strong>核心重點</strong>：StatementDog 數據顯示鉅橡營運週期 239.21 天，優於電子零組件製造業平均 364.37 天（領先約 34%）；然 PCB 同業平均僅 209.47 天，鉅橡落後約 14%。</li><li><strong>深度見解</strong>：此對位結果存在分類差異——鉅橡歸類為「電子零組件製造」時表現優於同業，但歸入「PCB 印刷電路板」時則落後。考慮鉅橡核心業務為散熱機構件（非純 PCB 製造），以 PCB 同業對位更具參考價值。存貨週轉率 0.65 次/年（2025 Q4），遠低於產業平均 4.51 次，反映產品去化能力薄弱。</li></ul><h3 id="四、毛利趨勢與存貨關聯性" tabindex="-1">四、毛利趨勢與存貨關聯性 <a class="header-anchor" href="#四、毛利趨勢與存貨關聯性" aria-label="Permalink to &quot;四、毛利趨勢與存貨關聯性&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025 年各季毛利率：Q1=21.7% → Q2=20.4% → Q3=23.0% → Q4=26.4%，呈現逐季改善趨勢。</li><li><strong>深度見解</strong>：毛利率逐季攀升與存貨週轉天數的關聯值得關注。Q4 毛利率達 26.4%（全年最高），同時 DIO 惡化至 562 天，暗示公司可能透過提高產品單價或優化產品組合來抵銷存貨壓力。然而，高毛利無法掩蓋資金效率低下的結構性問題——若存貨週轉無法持續改善，高毛利將被資金成本侵蝕。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一：現金週期過長侵蝕 ROE</strong>。503 天的現金週期意味著鉅橡需自行墊付約 1.4 年的營運資金。以 2025 年淨利約 130M TWD 估算，若將同等資金投入無風險標的（假設 2% 年化），機會成本約 10M TWD，佔淨利比重達 7.7%。此資金效率劣勢將長期壓制股東報酬率，除非 DIO 能大幅縮短至同業水準（~209 天），否則 ROE 難以突破 15% 門檻。</li><li><strong>空頭風險二：Q4 存貨週轉反轉預警</strong>。2025 Q3 曾達 500 天低點，惟 Q4 惡化至 562 天（+12.4%），且存貨餘額從 Q3 的 ~376M 回升。此反轉若持續，將使年度 DIO 重回 600 天以上。需關注 Q4 反轉是否與特定客戶訂單延遲交貨、原材料備料策略調整，或下游需求放緩有關。若為後者，2026 年存貨壓力可能進一步加劇。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind 財務分析工具</strong>：inventory_check 子功能，股號 8074，期間 2023-2025</li><li><strong>FinMind 原始數據</strong>：TaiwanStockBalanceSheet（存貨餘額）、TaiwanStockFinancialStatements（營業成本、應收/付帳款）、TaiwanStockMonthRevenue（月營收）</li><li><strong>查詢參數</strong>：stock_id=8074, start=2023-01-01, end=2026-04-30</li><li><strong>StatementDog 同業對位</strong>：鉅橡營運週期 239.21 天 vs 電子零組件平均 364.37 天、PCB 同業平均 209.47 天</li><li><strong>關鍵核對碼</strong>：2025 DIO=573 天, CCC=503 天, 存貨餘額=376M TWD</li></ul>',21)])])}const u=t(r,[["render",n]]);export{g as __pageData,u as default};
